[CmdletBinding(SupportsShouldProcess=$true)]
param([switch]$RestartClickToRun,[switch]$TriggerUpdate,[switch]$QuickRepair,[switch]$ClearOfficeCache,[switch]$Force,[string]$OutputPath="$env:USERPROFILE\Desktop\M365AppsRepair")
$ErrorActionPreference='Stop';New-Item -ItemType Directory -Path $OutputPath -Force|Out-Null;$Log=Join-Path $OutputPath ("repair-{0:yyyyMMdd-HHmmss}.log"-f(Get-Date));function L($m){"$(Get-Date -Format s) $m"|Tee-Object -FilePath $Log -Append};if(-not($RestartClickToRun-or$TriggerUpdate-or$QuickRepair-or$ClearOfficeCache)){throw'Choose at least one repair action.'}
Get-ItemProperty 'HKLM:\SOFTWARE\Microsoft\Office\ClickToRun\Configuration' -ErrorAction SilentlyContinue|Export-Clixml (Join-Path $OutputPath 'office-before.xml')
if($RestartClickToRun-and$PSCmdlet.ShouldProcess('ClickToRunSvc','Restart service')){Restart-Service ClickToRunSvc -Force;L'Click-to-Run service restarted.'}
if($TriggerUpdate){$client="$env:ProgramFiles\Common Files\Microsoft Shared\ClickToRun\OfficeC2RClient.exe";if(-not(Test-Path $client)){$client="${env:ProgramFiles(x86)}\Common Files\Microsoft Shared\ClickToRun\OfficeC2RClient.exe"};if(-not(Test-Path $client)){throw'OfficeC2RClient.exe not found.'};if($PSCmdlet.ShouldProcess('Microsoft 365 Apps','Trigger update')){Start-Process $client '/update user displaylevel=true forceappshutdown=false' -Wait;L'Office update requested.'}}
if($QuickRepair){$client="$env:ProgramFiles\Common Files\Microsoft Shared\ClickToRun\OfficeC2RClient.exe";if(-not(Test-Path $client)){$client="${env:ProgramFiles(x86)}\Common Files\Microsoft Shared\ClickToRun\OfficeC2RClient.exe"};if(-not(Test-Path $client)){throw'OfficeC2RClient.exe not found.'};if($PSCmdlet.ShouldProcess('Microsoft 365 Apps','Run quick repair')){Start-Process $client '/repair user displaylevel=true forceappshutdown=true' -Wait;L'Office quick repair completed.'}}
if($ClearOfficeCache){$p=Get-Process winword,excel,powerpnt,outlook,onenote -ErrorAction SilentlyContinue;if($p-and-not$Force){throw'Close Office apps or use -Force.'};if($p){$p|Stop-Process -Force};foreach($x in @("$env:LOCALAPPDATA\Microsoft\Office\16.0\OfficeFileCache","$env:LOCALAPPDATA\Microsoft\Office\Licenses")){if(Test-Path $x){if($PSCmdlet.ShouldProcess($x,'Clear Office cache')){Get-ChildItem $x -Force -ErrorAction SilentlyContinue|Remove-Item -Recurse -Force -ErrorAction SilentlyContinue}}};L'Office cache processed.'}
L'Repair workflow finished.'